-- Create test patient user
INSERT INTO user (openId, name, email, role, createdAt, updatedAt)
VALUES ('test-patient-001', 'John Patient', 'john.patient@test.com', 'user', NOW(), NOW())
ON DUPLICATE KEY UPDATE name = 'John Patient';

-- Get patient user ID
SET @patientUserId = (SELECT id FROM user WHERE email = 'john.patient@test.com' LIMIT 1);

-- Create patient record
INSERT INTO patients (userId, firstName, lastName, dateOfBirth, gender, phone, email, address, city, state, zipCode, emergencyContact, emergencyPhone, createdAt, updatedAt)
VALUES (@patientUserId, 'John', 'Patient', '1980-05-15', 'male', '555-0123', 'john.patient@test.com', '123 Test St', 'Test City', 'TC', '12345', 'Jane Patient', '555-0124', NOW(), NOW())
ON DUPLICATE KEY UPDATE firstName = 'John';

-- Get patient ID
SET @patientId = (SELECT id FROM patients WHERE email = 'john.patient@test.com' LIMIT 1);

-- Get physician ID (admin user)
SET @physicianId = (SELECT id FROM user WHERE role = 'admin' LIMIT 1);

-- Create care plan
INSERT INTO patient_care_plans (
  patientId, physicianId, title, diagnosis, goals, medications, lifestyle, monitoring,
  checkInFrequency, nextCheckInDate, status, startDate, sharedWithPatient, createdAt, updatedAt
)
VALUES (
  @patientId,
  @physicianId,
  'Type 2 Diabetes Management Plan',
  'Type 2 Diabetes Mellitus (E11.9)',
  JSON_ARRAY(
    'Reduce HbA1c to below 7%',
    'Lose 10-15 pounds over 3 months',
    'Exercise 30 minutes daily',
    'Monitor blood glucose twice daily'
  ),
  JSON_ARRAY(
    JSON_OBJECT('name', 'Metformin', 'dosage', '500mg', 'frequency', 'Twice daily with meals', 'instructions', 'Take with food to reduce stomach upset', 'startDate', NOW()),
    JSON_OBJECT('name', 'Lisinopril', 'dosage', '10mg', 'frequency', 'Once daily', 'instructions', 'Take in the morning', 'startDate', NOW())
  ),
  JSON_ARRAY(
    JSON_OBJECT('recommendation', 'Low-carb Mediterranean diet', 'frequency', 'Daily'),
    JSON_OBJECT('recommendation', 'Brisk walking or swimming', 'frequency', '30 minutes, 5 days per week'),
    JSON_OBJECT('recommendation', 'Blood glucose monitoring', 'frequency', 'Fasting and 2 hours post-meal')
  ),
  JSON_ARRAY(
    JSON_OBJECT('metric', 'HbA1c', 'frequency', 'Every 3 months'),
    JSON_OBJECT('metric', 'Blood pressure', 'frequency', 'Weekly'),
    JSON_OBJECT('metric', 'Weight', 'frequency', 'Weekly')
  ),
  'weekly',
  DATE_ADD(NOW(), INTERVAL 7 DAY),
  'active',
  NOW(),
  true,
  NOW(),
  NOW()
);

-- Get care plan ID
SET @carePlanId = LAST_INSERT_ID();

-- Create sample lab results
INSERT INTO patient_lab_results (
  patientId, testDate, labName, testResults, uploadedBy, uploadMethod, createdAt, updatedAt
)
VALUES
(
  @patientId,
  DATE_SUB(NOW(), INTERVAL 30 DAY),
  'Comprehensive Metabolic Panel',
  JSON_ARRAY(
    JSON_OBJECT('testName', 'HbA1c', 'value', '8.2', 'unit', '%', 'referenceRange', '4.0-5.6', 'flag', 'high'),
    JSON_OBJECT('testName', 'Fasting Glucose', 'value', '145', 'unit', 'mg/dL', 'referenceRange', '70-100', 'flag', 'high'),
    JSON_OBJECT('testName', 'Total Cholesterol', 'value', '210', 'unit', 'mg/dL', 'referenceRange', '<200', 'flag', 'high')
  ),
  @physicianId,
  'manual',
  NOW(),
  NOW()
),
(
  @patientId,
  DATE_SUB(NOW(), INTERVAL 7 DAY),
  'Follow-up Glucose',
  JSON_ARRAY(
    JSON_OBJECT('testName', 'HbA1c', 'value', '7.8', 'unit', '%', 'referenceRange', '4.0-5.6', 'flag', 'high'),
    JSON_OBJECT('testName', 'Fasting Glucose', 'value', '132', 'unit', 'mg/dL', 'referenceRange', '70-100', 'flag', 'high')
  ),
  @physicianId,
  'manual',
  NOW(),
  NOW()
);

-- Create sample check-in
INSERT INTO patient_check_ins (
  patientId, carePlanId, checkInDate, overallFeeling, symptoms, metrics,
  medicationsTaken, lifestyleAdherence, conversationSummary, alertGenerated, createdAt, updatedAt
)
VALUES (
  @patientId,
  @carePlanId,
  DATE_SUB(NOW(), INTERVAL 3 DAY),
  7,
  JSON_ARRAY(
    JSON_OBJECT('symptom', 'Fatigue', 'severity', 3, 'notes', 'Better than last week'),
    JSON_OBJECT('symptom', 'Increased thirst', 'severity', 2)
  ),
  JSON_ARRAY(
    JSON_OBJECT('metric', 'Weight', 'value', '185', 'unit', 'lbs'),
    JSON_OBJECT('metric', 'Fasting glucose', 'value', '128', 'unit', 'mg/dL')
  ),
  JSON_ARRAY(
    JSON_OBJECT('medication', 'Metformin', 'taken', true, 'missedDoses', 0),
    JSON_OBJECT('medication', 'Lisinopril', 'taken', true, 'missedDoses', 0)
  ),
  JSON_ARRAY(
    JSON_OBJECT('activity', 'Diet', 'adherence', 85),
    JSON_OBJECT('activity', 'Exercise', 'adherence', 70)
  ),
  'Patient reports feeling better overall. Glucose levels improving with medication. Still struggling with exercise routine but diet adherence is good.',
  false,
  NOW(),
  NOW()
);

-- Create progress metrics for the last 4 weeks
INSERT INTO patient_progress_metrics (
  patientId, carePlanId, periodStart, periodEnd, avgOverallFeeling, avgSymptomSeverity,
  medicationAdherence, lifestyleAdherence, checkInsCompleted, alertsGenerated, createdAt, updatedAt
)
VALUES
(@patientId, @carePlanId, DATE_SUB(NOW(), INTERVAL 28 DAY), DATE_SUB(NOW(), INTERVAL 21 DAY), 7.2, 2.5, 90, 80, 1, 0, NOW(), NOW()),
(@patientId, @carePlanId, DATE_SUB(NOW(), INTERVAL 21 DAY), DATE_SUB(NOW(), INTERVAL 14 DAY), 7.5, 2.3, 88, 82, 1, 0, NOW(), NOW()),
(@patientId, @carePlanId, DATE_SUB(NOW(), INTERVAL 14 DAY), DATE_SUB(NOW(), INTERVAL 7 DAY), 7.8, 2.1, 92, 85, 1, 0, NOW(), NOW()),
(@patientId, @carePlanId, DATE_SUB(NOW(), INTERVAL 7 DAY), NOW(), 8.0, 1.9, 95, 88, 1, 0, NOW(), NOW());

SELECT 'Test data created successfully!' AS status,
       @patientUserId AS patient_user_id,
       @patientId AS patient_id,
       @carePlanId AS care_plan_id;

